    def test_make_banner_escapes_hostile_source_names(self) -> None:
        banner = MODULE.make_banner(Path("/tmp/repo/.claude/skills/safe-skill/evil-->\n# injected.md"))

        self.assertIn("Source artifact: evil--\\>\\n# injected.md", banner)
        self.assertNotIn("Source artifact: evil-->\n# injected.md", banner)

    def test_redirected_skill_short_circuits_explicit_analysis(self) -> None:
        skill_packages = {
            "example-history-skill": {
                "SKILL.md": """\
                    ---
                    name: example-history-skill
                    description: "REDIRECTED to pattern-miner (mode:history)."
                    ---

                    # example-history-skill — REDIRECTED

                    **Replacement**: Use `pattern-miner` with `source:history` for commit history mining.
                """,
                "references/IMPLEMENTATION.md": """\
                    # Implementation

                    Task({
                      description: "legacy task",
                    })
                """,
            }
        }

        with temporary_repo(skill_packages):
            stdout = io.StringIO()
            with contextlib.redirect_stdout(stdout):
                result = MODULE.migrate_skill(
                    "example-history-skill",
                    dry_run=True,
                    analysis_only=True,
                )

        output = stdout.getvalue()
        self.assertEqual(result.status, "REDIRECTED")
        self.assertIn("example-history-skill: REDIRECTED", output)
        self.assertIn("replacement: Use `pattern-miner` with `source:history`", output)
        self.assertNotIn("inline Claude Task() site", output)

